import { motion } from "framer-motion";
import { useState } from "react";

export default function DayCard({ day, onUpdate }) {
  const [notes, setNotes] = useState(day.notes || "");

  return (
    <motion.div
      whileHover={{ scale: 1.02 }}
      className="bg-white shadow-md rounded-2xl p-4 mb-4"
    >
      <div className="flex justify-between items-center">
        <h3 className="font-semibold text-lg">Day {day.day_number}</h3>
        <input
          type="checkbox"
          checked={day.completed}
          onChange={(e) =>
            onUpdate(day.id, {
              completed: e.target.checked,
              notes,
            })
          }
        />
      </div>

      <p className="text-gray-600 mt-2">{day.task}</p>

      <textarea
        className="w-full mt-3 p-2 border rounded-lg"
        value={notes}
        onChange={(e) => setNotes(e.target.value)}
        placeholder="Notes..."
      />
    </motion.div>
  );
}
